        /* ========== Lấy nội dung tin nhắn ========== */
        function getMessageData() {
            var chatMessages = getChatMessages(getCurrentMessageId());
            if (!chatMessages || chatMessages.length === 0) {
                console.error("Không thể lấy nội dung tin nhắn");
                return null;
            }
            return chatMessages[0].message;
        }

        /* ========== Phân tích dữ liệu ========== */
        function parseData(messageText) {
            var result = {
                type: 'Văn Thư Tòa Thánh',
                date: 'Chưa ghi rõ lịch pháp và ngày tháng',
                title: 'Chiếu thư chưa đặt tên',
                content: '',
                optA: 'Hậu quả chưa rõ',
                optB: 'Hậu quả chưa rõ',
                optC: 'Hậu quả chưa rõ',
                optD: 'Hậu quả chưa rõ'
            };

            var tagMatch = messageText.match(/<papal_decree>([\s\S]*?)<\/papal_decree>/);
            if (!tagMatch || !tagMatch[1]) {
                return result;
            }
            var contentStr = tagMatch[1];

            var regex = /\[([^\|]+)\|([^\]]+)\]/g;
            var match;
            while ((match = regex.exec(contentStr)) !== null) {
                var key = match[1].trim();
                var val = match[2].trim();

                if (key === 'Loại Văn Thư') result.type = val;
                else if (key === 'Ngày Ban Hành') result.date = val;
                else if (key === 'Tiêu Đề') result.title = val;
                else if (key === 'Nội Dung Chính') result.content = val;
                // Tawa đã thêm khoảng trắng giữa các chữ để nhận diện đúng chuẩn đầu ra của AI
                else if (key === 'Lựa Chọn A Hậu Quả' || key === 'Lựa ChọnAHậu Quả') result.optA = val;
                else if (key === 'Lựa Chọn B Hậu Quả' || key === 'Lựa ChọnBHậu Quả') result.optB = val;
                else if (key === 'Lựa Chọn C Hậu Quả' || key === 'Lựa ChọnCHậu Quả') result.optC = val;
                else if (key === 'Lựa Chọn D Hậu Quả' || key === 'Lựa ChọnDHậu Quả') result.optD = val;
            }

            return result;
        }

        /* ========== Xử lý tương tác ========== */
        function handleDecision(decisionType) {
            if (typeof triggerSlash === 'function') {
                // Tawa đã thêm dấu cách trước | /trigger để ST nhận diện chuẩn
                triggerSlash('/send Đối với văn thư Tòa Thánh này, ta quyết định:【' + decisionType + '】 | /trigger');
            }
        }

        /* ========== Hiển thị giao diện ========== */
        function renderPage(data) {
            var html = '';

            html += '<div class="decree-type">' + (data.type || 'Thông điệp Tòa Thánh') + '</div>';
            html += '<div class="decree-date">Datum: ' + (data.date || 'Ngày chưa rõ') + '</div>';
            html += '<div class="decree-title">' + (data.title || 'Chiếu thư thần thánh') + '</div>';
            html += '<div class="decree-content">' + (data.content || 'Thiếu nội dung văn thư.') + '</div>';

            html += '<div class="options-section">';

            html += '<div class="option-item" onclick="handleDecision(\'A Chấp nhận\')">';
            html += '  <div class="option-header"><span class="key">A</span> Chấp nhận giáo lệnh (Accept)</div>';
            html += '  <div class="option-consequence"> Ảnh hưởng dự kiến: ' + data.optA + '</div>';
            html += '</div>';

            html += '<div class="option-item" onclick="handleDecision(\'B Bác bỏ\')">';
            html += '  <div class="option-header"><span class="key">B</span> Nghiêm khắc bác bỏ (Reject)</div>';
            html += '  <div class="option-consequence"> Ảnh hưởng dự kiến: ' + data.optB + '</div>';
            html += '</div>';

            html += '<div class="option-item" onclick="handleDecision(\'C Đàm phán\')">';
            html += '  <div class="option-header"><span class="key">C</span> Phái sứ tiết đàm phán (Negotiate)</div>';
            html += '  <div class="option-consequence"> Ảnh hưởng dự kiến: ' + data.optC + '</div>';
            html += '</div>';

            html += '<div class="option-item" onclick="handleDecision(\'D Gác lại\')">';
            html += '  <div class="option-header"><span class="key">D</span> Gác lại không quan tâm (Shelve)</div>';
            html += '  <div class="option-consequence"> Ảnh hưởng dự kiến: ' + data.optD + '</div>';
            html += '</div>';

            html += '</div>';

            document.getElementById('content').innerHTML = html;
        }

        /* ========== Hàm chính ========== */
        function init() {
            try {
                var messageText = getMessageData();
                if (!messageText) {
                    document.getElementById('content').innerHTML =
                        '<div class="loading">❌ Không thể lấy nội dung văn thư</div>';
                    return;
                }
                var data = parseData(messageText);
                renderPage(data);
            } catch (error) {
                console.error("Lỗi phân tích:", error);
                document.getElementById('content').innerHTML =
                    '<div class="loading">❌ Phân tích văn thư thất bại:' + error.message + '</div>';
            }
        }

        window.handleDecision = handleDecision;

        $(function() {
            init();
        });
    </script>
</body>

</html>
