    <script>
        function getMessageData() {
            var chatMessages = getChatMessages(getCurrentMessageId());
            if (!chatMessages || chatMessages.length === 0) {
                console.error("Không thể lấy nội dung tin nhắn");
                return null;
            }
            return chatMessages[0].message;
        }

        function parseData(messageText) {
            var result = {
                type: 'Công Văn Ngoại Giao',
                sender: 'Thế Lực Chưa Rõ',
                date: 'Chưa ghi rõ lịch pháp và ngày tháng',
                title: 'Văn Thư Không Tiêu Đề',
                content: '',
                optA: 'Chưa dự đoán phản ứng cụ thể',
                optB: 'Chưa dự đoán phản ứng cụ thể',
                optC: 'Chưa dự đoán phản ứng cụ thể',
                optD: 'Chưa dự đoán phản ứng cụ thể'
            };

            var tagMatch = messageText.match(/<diplomatic_missive>([\s\S]*?)<\/diplomatic_missive>/);
            if (!tagMatch || !tagMatch[1]) {
                return result;
            }
            var contentStr = tagMatch[1];

            var regex = /\[([^\|]+)\|([^\]]+)\]/g;
            var match;
            while ((match = regex.exec(contentStr)) !== null) {
                var key = match[1].trim();
                var val = match[2].trim();

                if (key === 'Loại Văn Thư') result.type = val;
                else if (key === 'Người Gửi') result.sender = val;
                else if (key === 'Ngày Gửi') result.date = val;
                else if (key === 'Tiêu Đề') result.title = val;
                else if (key === 'Nội Dung Chính') result.content = val;
                // Tawa đã thêm bộ lọc chống dính chữ cho AI
                else if (key === 'Lựa Chọn A Hậu Quả' || key === 'Lựa ChọnAHậu Quả') result.optA = val;
                else if (key === 'Lựa Chọn B Hậu Quả' || key === 'Lựa ChọnBHậu Quả') result.optB = val;
                else if (key === 'Lựa Chọn C Hậu Quả' || key === 'Lựa ChọnCHậu Quả') result.optC = val;
                else if (key === 'Lựa Chọn D Hậu Quả' || key === 'Lựa ChọnDHậu Quả') result.optD = val;
            }
            return result;
