            color: #212121;
        }

        .event-content {
            font-size: 15px;
            line-height: 1.6;
            margin-bottom: 25px;
            background-color: rgba(255, 255, 255, 0.4);
            padding: 15px;
            border-radius: 4px;
            border-left: 4px solid #8d6e63;
