        .option-item:hover:not(.disabled) {
            border-color: #5d4037;
            background-color: #efebe9;
            transform: translateY(-2px);
            box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1);
        }

        /* Cố định "Đã hiểu" Kiểu dáng tùy chọn nhạt hơn một chút */
        .opt-know {
            background-color: #f5f5f5;
            border-color: #e0e0e0;
        }

        .opt-know:hover:not(.disabled) {
            border-color: #9e9e9e;
        }

        .option-header {
            font-weight: bold;
            color: #3e2723;
            margin-bottom: 5px;
            display: flex;
            align-items: center;
        }

        .option-header::before {
            content: '➤';
            color: #8d6e63;
            margin-right: 8px;
            font-size: 14px;
        }

        .option-consequence {
            font-size: 13px;
            color: #795548;
            margin-left: 22px;
        }

        .loading {
            text-align: center;
            padding: 20px;
            color: #4a3728;
        }

        /* Kiểu dáng trạng thái khóa */
        .option-item.disabled {
            cursor: not-allowed;
            opacity: 0.6;
            filter: grayscale(80%);
