        .decision-overlay {
            display: none;
            position: absolute;
            top: -10px;
            left: -10px;
            right: -10px;
            bottom: -10px;
            background: rgba(244, 232, 209, 0.8);
            backdrop-filter: blur(3px);
            border-radius: 8px;
            z-index: 10;
            align-items: center;
            justify-content: center;
            flex-direction: column;
            border: 2px dashed #4a3728;
        }

        .decision-overlay.active {
            display: flex;
        }

        .decision-text {
            font-size: 18px;
            font-weight: bold;
            color: #3e2723;
            margin-bottom: 5px;
            background-color: #fff;
            padding: 10px 20px;
            border-radius: 4px;
            border: 2px solid #3e2723;
            box-shadow: 4px 4px 0 rgba(0, 0, 0, 0.1);
