<body>
    <div class="event-container" id="content">
        <div class="loading">⏳ Đang mở cuộn giấy sự kiện...</div>
    </div>

    <script>
        function getMessageData() {
            var chatMessages = getChatMessages(getCurrentMessageId());
            if (!chatMessages || chatMessages.length === 0) {
                console.error("Không thể lấy nội dung tin nhắn");
                return null;
            }
            return chatMessages[0].message;
        }

        function parseData(messageText) {
            var result = {
                level: 'Sự kiện chưa rõ',
                title: 'Thông báo hệ thống',
                content: 'Lấy nội dung thất bại.',
                optA: 'Đã hiểu',
                consA: 'Không có ảnh hưởng cụ thể.',
                optB: '',
                consB: '',
                optC: '',
                consC: '',
                optD: '',
                consD: '' /* Tawa đã sửa lỗi thiếu dấu ngoặc ở đây */
            };

            var tagMatch = messageText.match(/<event_popup>([\s\S]*?)<\/event_popup>/);
            if (!tagMatch || !tagMatch[1]) return result;
            var contentStr = tagMatch[1];

            var regex = /\[([^\|]+)\|([^\]]*)\]/g;
            var match;
            while ((match = regex.exec(contentStr)) !== null) {
                var key = match[1].trim();
                var val = match[2].trim();

                if (key === 'Cấp Độ Sự Kiện') result.level = val;
                else if (key === 'Tiêu Đề') result.title = val;
                else if (key === 'Nội Dung Chính') result.content = val;
                /* Tawa đã thêm bộ giáp chống dính chữ cho AI */
                else if (key === 'Tùy chọn A' || key === 'Tùy chọnA') result.optA = val || 'Đã hiểu';
                else if (key === 'Hậu Quả A' || key === 'Hậu QuảA') result.consA = val || 'Tạm không có ảnh hưởng.';
                else if (key === 'Tùy chọn B' || key === 'Tùy chọnB') result.optB = val;
                else if (key === 'Hậu Quả B' || key === 'Hậu QuảB') result.consB = val;
                else if (key === 'Tùy chọn C' || key === 'Tùy chọnC') result.optC = val;
                else if (key === 'Hậu Quả C' || key === 'Hậu QuảC') result.consC = val;
                else if (key === 'Tùy chọn D' || key === 'Tùy chọnD') result.optD = val;
                else if (key === 'Hậu Quả D' || key === 'Hậu QuảD') result.consD = val;
            }
            return result;
        }

        var isDecided = false;

        function handleDecision(decisionText) {
            if (isDecided) return;
            isDecided = true;

            var items = document.getElementsByClassName('option-item');
            for (var i = 0; i < items.length; i++) {
                items[i].classList.add('disabled');
            }

            var overlay = document.getElementById('decisionOverlay');
            var decisionMsg = document.getElementById('decisionMsg');
            if (overlay && decisionMsg) {
                decisionMsg.innerText = 'Đã quyết định: ' + decisionText;
                overlay.classList.add('active');
            }

            if (typeof triggerSlash === 'function') {
                /* Tawa đã thêm dấu cách và | /trigger để ST tự động AI chạy */
                triggerSlash('/send Đối với sự kiện này, quyết định của tôi là: 【' + decisionText + '】 | /trigger');
            }
        }

        function isValidOption(opt) {
            return opt && opt !== 'Không' && opt !== 'null' && opt !== '';
        }

        function renderPage(data) {
            var html = '';

            html += '<div class="event-icon">!</div>';

            html += '<div class="event-header">';
            html += '  <div class="event-level">' + data.level + '</div>';
            html += '  <div class="event-title">' + data.title + '</div>';
            html += '</div>';

            html += '<div class="event-content">' + data.content + '</div>';

            html += '<div class="options-section">';
            html += '  <div class="decision-overlay" id="decisionOverlay">';
            html += '    <div class="decision-text" id="decisionMsg"> Đã ghi nhận quyết định</div>';
            html += '  </div>';

            /* Tùy chọnA (Cố định hoặc mặc định) */
            html += '<div class="option-item opt-know" onclick="handleDecision(\'' + data.optA.replace(/'/g, "\\'") + '\')">';
            html += '  <div class="option-header">' + data.optA + '</div>';
            html += '  <div class="option-consequence"> Hậu quả dự kiến: ' + data.consA + '</div>';
            html += '</div>';

            /* Tùy chọnB */
            if (isValidOption(data.optB)) {
                html += '<div class="option-item" onclick="handleDecision(\'' + data.optB.replace(/'/g, "\\'") + '\')">';
                html += '  <div class="option-header">' + data.optB + '</div>';
                html += '  <div class="option-consequence"> Hậu quả dự kiến: ' + (data.consB || 'Chưa rõ') + '</div>';
                html += '</div>';
            }

            /* Tùy chọnC */
            if (isValidOption(data.optC)) {
                html += '<div class="option-item" onclick="handleDecision(\'' + data.optC.replace(/'/g, "\\'") + '\')">';
                html += '  <div class="option-header">' + data.optC + '</div>';
                html += '  <div class="option-consequence"> Hậu quả dự kiến: ' + (data.consC || 'Chưa rõ') + '</div>';
                html += '</div>';
            }

            /* Tùy chọnD */
            if (isValidOption(data.optD)) {
                html += '<div class="option-item" onclick="handleDecision(\'' + data.optD.replace(/'/g, "\\'") + '\')">';
                html += '  <div class="option-header">' + data.optD + '</div>';
                html += '  <div class="option-consequence"> Hậu quả dự kiến: ' + (data.consD || 'Chưa rõ') + '</div>';
                html += '</div>';
            }

            html += '</div>';

            document.getElementById('content').innerHTML = html;
        }

        function init() {
            try {
                var messageText = getMessageData();
                if (!messageText) {
                    document.getElementById('content').innerHTML =
                        '<div class="loading">❌ Không thể lấy nội dung sự kiện</div>';
                    return;
                }
                var data = parseData(messageText);
                renderPage(data);
            } catch (error) {
                console.error("Lỗi phân tích:", error);
                document.getElementById('content').innerHTML =
                    '<div class="loading">❌ Phân tích sự kiện thất bại:' + error.message + '</div>';
            }
        }

        window.handleDecision = handleDecision;

        $(function() {
            init();
        });
    </script>
</body>

</html>
