<body>
    <div class="diet-container" id="content">
        <div class="loading"> Đang mở cuộn giấy Nghị viện Đế quốc...</div>
    </div>

    <script>
        function getMessageData() {
            var chatMessages = getChatMessages(getCurrentMessageId());
            if (!chatMessages || chatMessages.length === 0) {
                console.error("Không thể lấy nội dung tin nhắn");
                return null;
            }
            return chatMessages[0].message;
        }

        function parseData(messageText) {
            var result = {
                basic: {},
                electors: [],
                voting: [],
                actions: []
            };

            var tagMatch = messageText.match(/<imperial_diet>([\s\S]*?)<\/imperial_diet>/);
            if (!tagMatch || !tagMatch[1]) return result;
            var content = tagMatch[1];

            var basicMatch = content.match(/<basic>([\s\S]*?)<\/basic>/);
            if (basicMatch && basicMatch[1]) {
                var basicLines = basicMatch[1].match(/\[(.*?)\]/g) || [];
                basicLines.forEach(function(line) {
                    var parts = line.slice(1, -1).split('|');
                    if (parts.length >= 2) result.basic[parts[0].trim()] = parts[1].trim();
                });
            }

            var electorMatch = content.match(/<electors>([\s\S]*?)<\/electors>/);
            if (electorMatch && electorMatch[1]) {
                var electorLines = electorMatch[1].match(/\[(.*?)\]/g) || [];
                electorLines.forEach(function(line) {
                    var parts = line.slice(1, -1).split('|');
                    if (parts.length >= 4) {
                        result.electors.push({
                            name: parts[0].trim(),
                            stance: parts[1].trim(),
                            faction: parts[2].trim(),
                            note: parts[3].trim()
                        });
                    }
                });
            }

            var votingMatch = content.match(/<voting>([\s\S]*?)<\/voting>/);
            if (votingMatch && votingMatch[1]) {
                var votingLines = votingMatch[1].match(/\[(.*?)\]/g) || [];
                votingLines.forEach(function(line) {
                    var parts = line.slice(1, -1).split('|');
                    if (parts.length >= 3) {
                        result.voting.push({
                            house: parts[0].trim(),
                            state: parts[1].trim(),
                            detail: parts[2].trim()
                        });
                    }
                });
            }

            var actionMatch = content.match(/<actions>([\s\S]*?)<\/actions>/);
            if (actionMatch && actionMatch[1]) {
                var actionLines = actionMatch[1].match(/\[(.*?)\]/g) || [];
                actionLines.forEach(function(line) {
                    var parts = line.slice(1, -1).split('|');
                    if (parts.length >= 2) {
                        result.actions.push({
                            title: parts[0].trim(),
                            desc: parts[1] ? parts.slice(1).join('|').trim() : ''
                        });
                    }
                });
            }

            return result;
        }

        function getStanceClass(stance) {
            if (stance.indexOf('Ủng hộ') !== -1 || stance.indexOf('Tán thành') !== -1) return 'stance-support';
            if (stance.indexOf('Phản đối') !== -1) return 'stance-oppose';
            return 'stance-neutral';
        }

        function getFactionClass(faction) {
            if (faction.indexOf('Công Giáo') !== -1) return 'faction-catholic';
            if (faction.indexOf('Luther') !== -1) return 'faction-lutheran';
            if (faction.indexOf('Calvin') !== -1) return 'faction-calvinist';
            return '';
        }

        function renderPage(data) {
            var html = '';

            html += '<div class="header">';
            html += '<div class="title">⚜️ Ghi chép Nghị viện Đế quốc ⚜️</div>';
            html += '<div style="font-size: 12px; color: #8b7355;">Reichstagsprotokoll</div>';
            html += '</div>';

            html += '<div class="basic-info">';
            html += '<div class="info-row"><span class="label"> Địa điểm hội nghị:</span>' + (data.basic['Địa Điểm Nghị Viện'] || 'Chưa rõ') + '</div>';
            html += '<div class="info-row"><span class="label"> Nghị Án Hiện Tại:</span>' + (data.basic['Nghị Án Hiện Tại'] || 'Tạm Không Có') + '</div>';
            html += '<div class="info-row"><span class="label"> Thái Độ Hoàng Đế:</span>' + (data.basic['Thái Độ Hoàng Đế'] || 'Không rõ') + '</div>';
            html += '</div>';

            html += '<div class="section-title"> Đại biểu tham dự và lập trường</div>';
            html += '<div class="elector-grid">';
            data.electors.forEach(function(elector) {
                html += '<div class="elector-card">';
                html += '<div class="elector-top">';
                html += '<div class="elector-name">' + elector.name + '</div>';
                html += '<div class="elector-faction ' + getFactionClass(elector.faction) + '">' + elector.faction + '</div>';
                html += '<div class="elector-stance ' + getStanceClass(elector.stance) + '">' + elector.stance + '</div>';
                html += '</div>';
                html += '<div class="elector-note">💬 ' + elector.note + '</div>';
                html += '</div>';
            });
            html += '</div>';

            html += '<div class="section-title"> Tiến độ biểu quyết ba viện</div>';
            html += '<div class="voting-status">';
            data.voting.forEach(function(vote) {
                html += '<div class="vote-card">';
                html += '<div class="vote-house">' + vote.house + '</div>';
                html += '<div class="vote-state">' + vote.state + '</div>';
                html += '<div class="vote-detail">' + vote.detail + '</div>';
                html += '</div>';
            });
            html += '</div>';

            if (data.actions.length > 0) {
                html += '<div class="section-title"> Đối sách khả thi hiện tại</div>';
                html += '<div class="actions-panel">';
                data.actions.forEach(function(action) {
                    /* Tawa đã thêm .replace(/"/g, "&quot;") để kháng luôn cả ngoặc kép của AI! */
                    var safeAction = action.title.replace(/'/g, "\\'").replace(/"/g, "&quot;");
                    html += '<div class="action-btn" onclick="handleClick(\'' + safeAction + '\')">';
                    html += '<span class="action-title">📜 ' + action.title + '</span>';
                    html += '<span class="action-desc">' + action.desc + '</span>';
                    html += '</div>';
                });
                html += '</div>';
            }

            document.getElementById('content').innerHTML = html;
        }

        function handleClick(action) {
            if (typeof triggerSlash === 'function') {
                triggerSlash('/send Đối với vấn đề của Nghị viện, ta quyết định:【' + action + '】 | /trigger');
            }
        }

        function init() {
            try {
                var messageText = getMessageData();
                if (!messageText) {
                    document.getElementById('content').innerHTML =
                        '<div class="loading">❌ Không thể lấy hồ sơ văn thư</div>';
                    return;
                }
                var data = parseData(messageText);
                renderPage(data);
            } catch (error) {
                console.error("Lỗi:", error);
                document.getElementById('content').innerHTML =
                    '<div class="loading">❌ Cuộn giấy bị hỏng:' + error.message + '</div>';
            }
        }

        $(function() {
            init();
        });
    </script>
</body>

</html>
