                html += '<div class="factions-grid">';
                data.factions.forEach(function(fac) {
                    var cssClass = fac.name.indexOf('Công Giáo') !== -1 ? 'faction-catholic' : 'faction-protestant';
                    html += '<div class="faction-box ' + cssClass + '">';
                    html += '<div class="faction-name">' + fac.name + '</div>';
                    html += '<div class="faction-status"> Độ Gắn Kết: ' + fac.status + '</div>';
                    html += '<div class="faction-desc">' + fac.desc + '</div>';
                    html += '</div>';
                });
                html += '</div>';
            }

            if (data.reps.length > 0) {
                html += '<div class="section-title"> Phát Biểu Của Đại Biểu Tích Cực</div>';
                html += '<div class="reps-list">';
                data.reps.forEach(function(rep) {
                    html += '<div class="rep-card">';
                    html += '<div class="rep-top">';
                    html += '<div class="rep-name">' + rep.name + '</div>';
                    html += '<div class="rep-tag">' + rep.faction + '</div>';
                    html += '</div>';
                    html += '<div class="rep-speech">💬 "' + rep.speech + '"</div>';
                    html += '</div>';
                });
                html += '</div>';
            }

            if (data.actions.length > 0) {
                html += '<div class="section-title"> Thực Hiện Hành Động</div>';
                html += '<div class="actions-panel">';
                data.actions.forEach(function(act) {
                    /* Tawa đã gắn khiên bảo vệ chống lỗi dấu nháy đơn và nháy kép của AI */
                    var safeAct = act.title.replace(/'/g, "\\'").replace(/"/g, "&quot;");
                    html += '<div class="action-btn" onclick="handleClick(\'' + safeAct + '\')">';
                    html += '<span class="action-title">🖋️ ' + act.title + '</span>';
                    html += '<span class="action-desc">' + act.desc + '</span>';
                    html += '</div>';
                });
                html += '</div>';
            }

            document.getElementById('content').innerHTML = html;
        }

        function handleClick(action) {
            if (typeof triggerSlash === 'function') {
                /* Tawa đã thêm dấu cách và ngoặc vuông để AI nhận lệnh mượt mà nhất */
                triggerSlash('/send Quyết định hành động tại Nghị Viện Chư Hầu:【' + action + '】 | /trigger');
            }
        }

        function init() {
            try {
                var messageText = getMessageData();
                if (!messageText) {
                    document.getElementById('content').innerHTML = '<div class="loading">❌ Không thể lấy hồ sơ</div>';
                    return;
                }
                var data = parseData(messageText);
                renderPage(data);
            } catch (error) {
                console.error("Lỗi:", error);
                document.getElementById('content').innerHTML = '<div class="loading">❌ Hồ sơ bị hỏng:' + error.message + '</div>';
            }
        }

        $(function() {
            init();
        });
    </script>
</body>

