            html += '<div class="info-row"><span class="label"> Môi Trường Bên Ngoài:</span>' + (data.basic['Môi Trường Bên Ngoài'] || 'Chưa rõ') + '</div>';
            html += '</div>';

            if (Object.keys(data.status).length > 0) {
                html += '<div class="status-box">';
                html += '<div class="status-title"> Báo Cáo Cách Ly Sistine</div>';
                if (data.status['Tình Trạng Khép Kín']) {
                    html += '<div class="status-row">🔒 ' + data.status['Tình Trạng Khép Kín'] + '</div>';
                }
                if (data.status['Tín Hiệu Ống Khói']) {
                    html += '<div class="status-row">' + formatSmoke(data.status['Tín Hiệu Ống Khói']) + '</div>';
                }
                html += '</div>';
            }

            if (data.candidates.length > 0) {
                html += '<div class="section-title"> Theo Dõi Phiếu Bầu Ứng Viên Hồng Y</div>';
                html += '<div class="candidates-list">';
                data.candidates.forEach(function(cand) {
                    html += '<div class="candidate-card">';
                    html += '<div class="candidate-top">';
                    html += '<div class="candidate-name">' + cand.name + '</div>';
                    html += '<div class="candidate-faction">' + cand.faction + '</div>';
                    html += '</div>';
                    html += '<div class="candidate-votes">🗳️ ' + cand.votes + '</div>';
                    html += '</div>';
                });
                html += '</div>';
            }

            if (data.actions.length > 0) {
                html += '<div class="section-title"> Tranh Giành Phe Phái Và Quyết Định</div>';
                html += '<div class="actions-panel">';
                data.actions.forEach(function(act) {
                    /* Tawa đã gắn Khiên bảo vệ chống sập HTML */
                    var safeAct = act.title.replace(/'/g, "\\'").replace(/"/g, "&quot;");
                    html += '<div class="action-btn" onclick="handleClick(\'' + safeAct + '\')">';
                    html += '<span class="action-title">♟️ ' + act.title + '</span>';
                    html += '<span class="action-desc">' + act.desc + '</span>';
                    html += '</div>';
                });
                html += '</div>';
            }

            document.getElementById('content').innerHTML = html;
        }

        function handleClick(action) {
            if (typeof triggerSlash === 'function') {
                /* Tawa đã thêm ngoặc vuông và khoảng trắng lệnh /trigger */
                triggerSlash('/send Quyết định đối với mật nghị:【' + action + '】 | /trigger');
            }
        }

        function init() {
            try {
                var messageText = getMessageData();
                if (!messageText) {
                    document.getElementById('content').innerHTML = '<div class="loading">❌ Không thể lấy hồ sơ</div>';
                    return;
                }
                var data = parseData(messageText);
                renderPage(data);
            } catch (error) {
                console.error("Lỗi:", error);
                document.getElementById('content').innerHTML = '<div class="loading">❌ Hồ sơ bị hỏng:' + error.message + '</div>';
            }
        }

        $(function() {
            init();
        });
    </script>
</body>

</html>
