        function getClassAsset(cName) {
            if (cName.includes('Quốc gia') || cName.includes('Tuyển hầu') || cName.includes('Đại chủ') || cName.includes('Quốc vương') || cName.includes('Công tước') || cName.includes('Quyền thần') || cName.includes('Tổng đốc')) return {
                asset: 'Lãnh địa cung đình khổng lồ và quyền thu thuế tỉnh',
                income: '20000~50000 Ducat/Năm'
            };
            if (cName.includes('Bá tước') || cName.includes('Quý tộc') || cName.includes('Huân quý') || cName.includes('Địa chủ') || cName.includes('Pasha')) return {
                asset: 'Trang viên thế tập rộng lớn và lãnh địa nông nô',
                income: '3000~8000 Ducat/Năm'
            };
            if (cName.includes('Cự thương') || cName.includes('Đầu sỏ') || cName.includes('Thương gia') || cName.includes('Ngân hàng') || cName.includes('Chủ mỏ') || cName.includes('VOC')) return {
                asset: 'Cổ phần hội thương gia xuyên quốc gia và kho bãi cảng biển rộng lớn',
                income: '10000~30000 Ducat/Năm'
            };
            if (cName.includes('Giáo sĩ') || cName.includes('Giám mục') || cName.includes('Linh mục') || cName.includes('Xét xử') || cName.includes('Thẩm phán') || cName.includes('Mục sư')) return {
                asset: 'Thái ấp giáo khu hoặc vùng quản lý của tu viện',
                income: '1500~4000 Ducat/Năm'
            };
            if (cName.includes('Thống soái') || cName.includes('Trưởng quan') || cName.includes('Sĩ quan') || cName.includes('Tổng binh') || cName.includes('Tư lệnh') || cName.includes('Đề đốc')) return {
                asset: 'Thái ấp đồn trú biên giới và chiến lợi phẩm phong phú',
                income: '800~2000 Ducat/Năm'
            };
            if (cName.includes('Lính đánh thuê') || cName.includes('Đại đội trưởng') || cName.includes('Sát thủ') || cName.includes('Thợ săn') || cName.includes('Hiệp sĩ')) return {
                asset: 'Lều quân sự đóng quân khắp nơi và vàng của người thuê',
                income: '200~500 Ducat/Năm'
            };
            if (cName.includes('Binh lính') || cName.includes('Thủy thủ') || cName.includes('Người dẫn đường') || cName.includes('Lính gác')) return {
                asset: 'Vũ trang cá nhân tinh nhuệ và chăn đệm rách nát',
                income: '20~50 Ducat/Năm'
            };
            if (cName.includes('Học giả') || cName.includes('Thợ thủ công') || cName.includes('Quan lại') || cName.includes('Sứ giả') || cName.includes('Giảng viên') || cName.includes('Kiến trúc sư')) return {
                asset: 'Dinh thự độc lập trong thành và điền sản ít ỏi',
                income: '100~300 Ducat/Năm'
            };
            if (cName.includes('Thị dân') || cName.includes('Bình dân') || cName.includes('Người tị nạn') || cName.includes('Dị giáo') || cName.includes('Con hoang')) return {
                asset: 'Căn xưởng chật hẹp hoặc lang thang trên đường phố',
                income: '5~15 Ducat/Năm'
            };
            return {
                asset: 'Một số vật dụng cá nhân',
                income: '10~50 Ducat/Năm'
            };
        }

