        /* ============ Công cụ kết xuất ============ */
        function renderCardGridGeneric(id, list, groupKey, extraClass = "") {
            const el = document.getElementById(id);
            if (!el) return;
            el.innerHTML = '';
            list.forEach(item => {
                let div = document.createElement('div');
                div.className = 'card ' + extraClass;
                let cTitle = `<div class="card-title"${extraClass==='nsfw-card' ? ' style="color:#b0416b;"' : (extraClass==='merc-card' ? ' style="color:#82a8bc;"' : '')}>${item.title}</div>`;
                if (item.year) {
                    cTitle = `<div class="script-card-title"${extraClass==='nsfw-card' ? ' style="color:#b0416b;"' : (extraClass==='merc-card' ? ' style="color:#82a8bc;"' : '')}><span class="script-year"${extraClass==='nsfw-card' ? ' style="color:#d67ba0;"' : (extraClass==='merc-card' ? ' style="color:#a8c6d7;"' : '')}>${item.year}</span><span class="script-name">${item.name}</span></div>`;
                }

                let classAddition = "";
                if (groupKey === 'class' && item.asset) {
                    classAddition = `<div class="class-asset">Tài sản lãnh địa: ${item.asset}</div><div class="class-income">Thuế thu nhập hàng năm: ${item.income}</div>`;
                }

                div.innerHTML = `${cTitle}<div class="card-desc">${item.desc}</div>${classAddition}`;
                div.onclick = function() {
                    document.querySelectorAll(`#${id} .card`).forEach(c => c.classList.remove('selected'));
                    div.classList.add('selected');
                    let customId = id.replace('cards-', 'inp-') + '-custom';
                    if (document.getElementById(customId)) document.getElementById(customId).value = '';
                    uData[groupKey] = item.title || `${item.year} - ${item.name}`;

                    if (id === 'cards-script' || id === 'cards-merc-script') {
                        if (item.macro) uData.macro = item.macro;
                    }

                    if (groupKey === 'class' && item.asset) {
                        uData.asset = item.asset;
                        uData.income = item.income;
                    }

                    if (id === 'cards-tgt-script') {
                        curTgtScript = item;
                        renderCardGridGeneric('cards-tgt-target', item.targets, 'tgtTarget', 'nsfw-card');
                        renderCardGridGeneric('cards-tgt-action', item.actions, 'tgtAction', 'nsfw-card');
                    }
                    if (id === 'cards-sb-script') {
                        curSbScript = item;
                        renderCardGridGeneric('cards-sb-city', item.cities, 'sbCity', 'nsfw-card');
                        renderCardGridGeneric('cards-sb-class', item.classes, 'sbClass', 'nsfw-card');
                        renderCardGridGeneric('cards-sb-project', item.projects, 'sbProject', 'nsfw-card');
                    }
                };
                el.appendChild(div);
            });
        }

