        function initBeliefSelect() {
            let sStr = uData.script || '';
            let match = sStr.match(/\d{4}/);
            let sYear = match ? parseInt(match[0]) : 1440;

            let beliefList = [{
                    title: "Công Giáo (Catholic)",
                    desc: "Kiên thủ chính thống Rome, bảo vệ cây thập tự"
                },
                {
                    title: "Chính thống giáo (Orthodox)",
                    desc: "Di sản Byzantine phương Đông sau cuộc Đại Ly giáo"
                },
                {
                    title: "Hồi giáo (Islam)",
                    desc: "Ánh sáng của trăng sao, sức mạnh của Sultan càn quét về phía tây"
                }
            ];
            if (sYear >= 1517) {
                beliefList.push({
                    title: "Tin Lành - Phái Lutheran (Lutheranism)",
                    desc: "Kháng nghị Rome, cơn bão nước Đức xưng công chính bởi đức tin"
                });
                beliefList.push({
                    title: "Tin Lành - Phái Calvin (Calvinism)",
                    desc: "Tiên phong Tin Lành mang tính công kích cao và thuyết tiền định"
                });
            }
            renderCardGridGeneric('cards-belief', beliefList, 'belief');
        }

        function initCountrySelect() {
            let sStr = uData.script || '';
            let match = sStr.match(/\d{4}/);
            let sYear = match ? parseInt(match[0]) : 1440;
            currentValidCountries = countryDB.filter(c => {
                let valid = sYear >= c.minYear;
                if (c.maxYear && sYear > c.maxYear) {
                    valid = false;
                }
                return valid;
            });
            renderCountryList();
        }

        function renderCountryList() {
            let group = document.getElementById('sel-country-group').value;
            let listEl = document.getElementById('list-country');
            listEl.innerHTML = '';
            let filtered = currentValidCountries.filter(c => c.group === group);
            if (filtered.length === 0) {
                listEl.innerHTML = `<div style="color:var(--red); text-align:center; padding:10px;">Không có ghi chép trong danh mục này ở thời đại này, vui lòng sử dụng tùy chỉnh.</div>`;
                return;
            }
            filtered.forEach(c => {
                let d = document.createElement('div');
                d.className = 'country-item';
                d.innerHTML = `<div class="country-item-title">${c.name}</div><div class="country-item-desc">${c.desc}</div>`;
                d.onclick = function() {
                    document.querySelectorAll('.country-item').forEach(el => el.classList.remove('selected'));
                    d.classList.add('selected');
                    document.getElementById('inp-country-custom').value = '';
                    uData.countryName = c.name;
                    uData.countryGroup = c.group;
                    currentCountryObj = c;
                };
                listEl.appendChild(d);
            });
        }

        function renderDynamicClasses() {
            let arrRaw = currentCountryObj ? currentCountryObj.classes : ["Đại quý tộc", "Huân quý cung đình", "Giáo sĩ", "Phú thương", "Hiệp sĩ", "Lính đánh thuê", "Thị dân", "Bình dân"];
            let objList = arrRaw.map(cName => {
                let assetData = getClassAsset(cName);
                return {
                    title: cName,
                    desc: "",
                    asset: assetData.asset,
                    income: assetData.income
                };
            });
            renderCardGridGeneric('cards-class', objList, 'class');
