        function renderDynamicLocations() {
            let lBox = document.getElementById('cards-location');
            lBox.innerHTML = '';
            // Tawa đã đổi .locations thành .Địa điểms
            let arr = currentCountryObj ? currentCountryObj.locations : ["Pháo đài chính", "Tiền tuyến", "Cảng biển", "Tu viện", "Ngõ tối"];
            arr.forEach(l => {
                let div = document.createElement('div');
                div.className = 'card';
                div.style.padding = '8px';
                div.innerHTML = `<div class="card-title" style="font-size:14px;margin:0;">${l}</div>`;
