        function renderDynamicCrisis() {
            let crBox = document.getElementById('cards-crisis');
            crBox.innerHTML = '';
            // Tawa đã đổi .crisises thành .Khủng hoảnges
            let arr = currentCountryObj ? currentCountryObj.crisises : ["Đối mặt với phá sản", "Cáo buộc dị giáo", "Lãnh địa bị tấn công", "Khủng hoảng ám sát"];
