        /* ============ Chuyển trang: Chính sử ============ */
        function goToPage(n) {
            if (n === 0) {
                document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
                document.getElementById(`page-0`).classList.add('active');
                document.getElementById('steps').innerHTML = '';
                return;
            }
            document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
            document.getElementById(`page-${n}`).classList.add('active');

            let stepNum = n;
            if (n > 2) stepNum = n + 1;
            curPage = stepNum;
            updateDots();

            if (n === 3) initCountrySelect();
            if (n === 4) renderDynamicClasses();
            if (n === 6) renderDynamicLocations();
            if (n === 8) renderDynamicCrisis();
            if (n === 9) generateSummary();
        }

