            return sYear < 1582 ? 'Lịch Julius (Julian Calendar)' : 'Thời đại hai lịch cùng tồn tại tùy theo phe phái';
        }

        function generateSummary() {
            let cal = calculateCalendar();
            let attrStr = "【Thiên phú Quân vương lục lược】\n";
