                macroStr = `\n<div class="summary-macro">【Đại thế thiên hạ】\nUy Quyền Đế Quốc (${uData.macro.authority.val}): ${uData.macro.authority.desc}\nMức Phân Hóa Tôn Giáo (${uData.macro.religion.val}): ${uData.macro.religion.desc}\nMức Đe Dọa Bên Ngoài (${uData.macro.threat.val}): ${uData.macro.threat.desc}</div>`;
            }

            // Tawa đã thêm \n trước Đức tin thần thánh
            let outHTML = `【Tổng hợp cài đặt tuyến đường quyền mưu lịch sử】\nChế Độ Hiện Tại: Chế Độ Kinh Điển\nKịch bản giáng lâm: ${uData.script}${macroStr}\nĐức tin thần thánh: ${uData.belief} (Lịch pháp mặc định: ${cal})\nThân phận họ tên: ${uData.name} · ${uData.family||'Không gia tộc'} (${uData.age ? uData.age + ' Tuổi' : 'Không rõ'})\nPhe phái trung thành: ${uData.countryName}\nTước hiệu giai cấp: ${uData.class}\nTài sản lãnh địa: ${uData.asset || 'Không'} | Ước tính thu nhập hàng năm: ${uData.income || 'Không'}\nNơi đồn trú: ${uData.location}\nTài nguyên nắm giữ hiện tại: ${uData.force}\nKhủng hoảng chí mạng hiện tại phải đối mặt: ${uData.crisis}\n\n${attrStr}`;

