            if (routeMode === 'nsfw-sandbox' || routeMode === 'nsfw-target') baseClass += 'step-nsfw ';
            if (routeMode === 'mercenary') baseClass += 'step-merc ';
            el.className = baseClass;

            let total = totalPagesNormal;
            if (routeMode === 'nsfw-sandbox') total = totalPagesSb;
            if (routeMode === 'nsfw-target') total = totalPagesTgt;
            if (routeMode === 'mercenary') total = totalPagesMerc;

            for (let i = 0; i < total; i++) {
                let d = document.createElement('div');
                d.className = 'step-dot';
                if (i < curPage) d.classList.add('done');
                if (i === curPage) d.classList.add('active');
                el.appendChild(d);
