    </style>
    <script type="module">
        function determineStatusColor(val, type) {
            const v = String(val);
            if (type === 'Sĩ Khí' || type === 'Huấn Luyện') {
                if (['Cuồng Nhiệt', 'Tinh Nhuệ Hoàn Hảo'].includes(v)) return 'badge-good';
                if (['Vô Cảm', 'Mới Thành Đội Hình'].includes(v)) return 'badge-warn';
                if (['Kích Động', 'Binh Biến', 'Rời Rạc Vô Trật Tự'].includes(v)) return 'badge-bad';
            }
            if (type === 'Hậu Cần') {
                if (v === 'Tiếp Tế Dồi Dào') return 'badge-good';
                if (v === 'Cố Gắng Cầm Cự') return 'badge-warn';
                if (v === 'Cực Kỳ Thiếu Thốn') return 'badge-bad';
            }
            if (type === 'Thái Độ') {
                if (['Tín nhiệm', 'Ủng hộ', 'Cuồng Nhiệt'].includes(v)) return 'badge-good';
                if (['Cảnh giác', 'Dao động', 'Bất mãn'].includes(v)) return 'badge-warn';
                if (['Địch ý', 'Căm hận', 'Nổi loạn'].includes(v)) return 'badge-bad';
            }
            return 'badge-neutral';
        }

        /* Tương tác cửa sổ hành động lính đánh thuê */
        window.handleAction = function(keyword, param) {
            $('.modal-overlay').fadeOut(150);
            if (typeof triggerSlash === 'function') {
                let cmd = '/send [Hành động hệ thống] ' + keyword;
                if (param) cmd += ':' + param;
                triggerSlash(cmd + '|/trigger');
            } else {
                console.warn("Không phát hiện triggerSlash,Không thể gửi lệnh:", keyword, param);
            }
        };

        window.openModal = function(modalId) {
            $('.modal-overlay').hide();
            $('#' + modalId).fadeIn(200).css('display', 'flex');
        };

        window.openArmyModal = function(actionName, riskText) {
            $('#a-title').text(actionName);
            $('#a-risk').text(riskText);
            $('#btn-execute-army').attr('onclick', `handleAction('Quân lệnh', '${actionName}')`);
            openModal('modal-army');
        };

        /* Mở nơi đồn trúNPCCửa sổ thông tin chi tiết */
        window.openNpcModal = function(npcType) {
            const vars = _.get(getAllVariables(), 'stat_data', {});
            const npcData = _.get(vars, `Nhân Sự Đồn Trú.${npcType}`, {});

            const name = npcData['Họ Tên'] || 'Chưa có tên';
            const job = npcData['Chức Trách'] || npcType;
            const fav = npcData['Độ Hảo Cảm'] !== undefined ? npcData['Độ Hảo Cảm'] : '0';
            const evalText = npcData['Đánh Giá'] || 'Tạm không có lịch sử đánh giá';
            const descText = npcData['Giải Thích'] || 'Đại diện này nắm giữ một phần lợi ích địa phương, hãy cẩn thận giao thiệp.';

            $('#m-name-modal').text(name);
            $('#m-job-modal').text(job);
            $('#m-fav-modal').text(fav);

            $('#m-age-container').hide();
            $('#m-sex-container').hide();
            $('#m-attrs-container').hide();

            $('#m-eval').text(evalText);
            $('#m-desc').text(descText);

            openModal('char-modal');
        };

        function populateData() {
            const vars = _.get(getAllVariables(), 'stat_data', {});
            const setText = (id, val) => $(id).text(val !== undefined && val !== null && val !== '' ? val : 'N/A');
            const setHtml = (id, html) => $(id).html(html);

            /* ========================== Đọc chế độ ========================== */
            const currentMode = _.get(vars, 'Chế Độ Hiện Tại', 'Chế Độ Kinh Điển');
            const targetModeId = currentMode === 'Chế Độ Lính Đánh Thuê' ? 'mode-merc' : 'mode-lord';

            $('.mode-tab').removeClass('active');
            $('.mode-tab[data-mode="' + targetModeId + '"]').addClass('active');

            $('.mode-container').removeClass('active');
            $('#' + targetModeId).addClass('active');

            const player = _.get(vars, 'Thông Tin Người Chơi', {});
            const world = _.get(vars, 'Cục Diện Thế Giới', {});

            /* ========================== Phân tích dữ liệu chế độ lãnh chúa ========================== */

            setText('#w-year', _.get(world, ['Thời Gian', 'Năm']));

            let calRaw = String(_.get(world, ['Thời Gian', 'Lịch Pháp']) || 'Tạm Không Có');
            if (calRaw.includes('/') || calRaw.includes('|')) {
                let parts = calRaw.split(/[\/|]/).map(s => s.trim());
                setHtml('#w-cal', `${parts[0]}<br><span style="font-size:10px; color:#736453; font-weight:normal; display:inline-block; margin-top:2px;">${parts.slice(1).join('<br>')}</span>`);
            } else {
                setText('#w-cal', calRaw);
            }

            setText('#w-auth', _.get(world, ['Trạng Thái Vĩ Mô', 'Uy Quyền Đế Quốc', 'Chỉ Số']));
            setText('#w-auth-desc', _.get(world, ['Trạng Thái Vĩ Mô', 'Uy Quyền Đế Quốc', 'Mô Tả']));
            setText('#w-relig', _.get(world, ['Trạng Thái Vĩ Mô', 'Mức Phân Hóa Tôn Giáo', 'Chỉ Số']));
            setText('#w-relig-desc', _.get(world, ['Trạng Thái Vĩ Mô', 'Mức Phân Hóa Tôn Giáo', 'Mô Tả']));
            setText('#w-threat', _.get(world, ['Trạng Thái Vĩ Mô', 'Mức Đe Dọa Bên Ngoài', 'Chỉ Số']));
            setText('#w-threat-desc', _.get(world, ['Trạng Thái Vĩ Mô', 'Mức Đe Dọa Bên Ngoài', 'Mô Tả']));
            setText('#w-sit', world['Tình Hình Hiện Tại'] || 'Sóng yên biển lặng');
            setText('#w-dil', world['Khó Khăn Hiện Tại'] || 'Tạm không có khủng hoảng');

            const natDyn = Object.entries(world['Động Thái Quốc Gia'] || {}).map(([k, v]) =>
                `<div class="list-item"><b style="color:var(--wax-red);">${k}:</b> <span style="color:#5a5045;">${v}</span></div>`
            ).join('');
            setHtml('#list-nation-dyn', natDyn || '<div class="list-item" style="text-align:center;"> Tạm không có động thái</div>');

            setText('#p-name', _.get(player, ['Hồ Sơ Gia Tộc', 'Tên'], 'Chưa có tên'));
            setText('#p-family', _.get(player, ['Hồ Sơ Gia Tộc', 'Tên Gia Tộc'], 'Không có gia tộc'));
            setText('#p-age', _.get(player, ['Hồ Sơ Gia Tộc', 'Tuổi']));
            setText('#p-motto', `"${_.get(player, ['Hồ Sơ Gia Tộc', 'Châm Ngôn Gia Tộc'])}"`);
            setText('#p-state', _.get(player, ['Bối Cảnh Cơ Bản', 'Quốc Gia']));
            setText('#p-class', _.get(player, ['Bối Cảnh Cơ Bản', 'Giai Cấp'], 'Hiệp sĩ'));
            setText('#p-faith', _.get(player, ['Bối Cảnh Cơ Bản', 'Tín Ngưỡng Tôn Giáo']));
            setText('#p-land', _.get(player, ['Bối Cảnh Cơ Bản', 'Lãnh Địa']));
            setText('#p-job', _.get(player, ['Bối Cảnh Cơ Bản', 'Chức Vụ']));

            const titles = Object.entries(_.get(player, ['Danh Hiệu Và Lý Lịch', 'Danh Hiệu'], {})).map(([k, v]) =>
                `<div class="list-item"><b>${k}</b> <br><span style="font-size:11px;color:#736453;">${v}</span></div>`
            ).join('');
            setHtml('#list-titles', titles || '<div class="list-item"> Không có danh hiệu</div>');

            const histories = Object.entries(_.get(player, ['Danh Hiệu Và Lý Lịch', 'Lý Lịch'], {})).map(([k, v]) =>
                `<div class="list-item"><b>${k}</b>: <span style="font-size:11px;color:#736453;">${v}</span></div>`
            ).join('');
            setHtml('#list-histories', histories || '<div class="list-item"> Không có lý lịch quá khứ</div>');

            const stats = _.get(vars, 'Thuộc Tính Năng Lực', {});

            // Hiển thị thanh tiến trình thuộc tính hai chiều (-100 ~ 100)
            const renderStat = (id, label, val) => {
                const num = Number(val) || 0;
                let barHtml = '';
                const color = num >= 0 ? 'var(--status-good)' : 'var(--status-bad)';
                if (num >= 0) {
                    const pct = Math.min((num / 100) * 50, 50);
                    barHtml = `<div style="position:absolute; left:50%; width:${pct}%; height:100%; background-color:${color}; transition: width 0.5s;"></div>`;
                } else {
                    const pct = Math.min((Math.abs(num) / 100) * 50, 50);
                    barHtml = `<div style="position:absolute; right:50%; width:${pct}%; height:100%; background-color:${color}; transition: width 0.5s;"></div>`;
                }
                return `
          <div class="attr-container">
            <div class="attr-header"><span>${label}</span><b style="color:${color}">${num > 0 ? '+' : ''}${num}</b></div>
            <div class="attr-bar-bg">
              <div style="position:absolute; left:50%; width:1px; height:100%; background:rgba(0,0,0,0.3); z-index:2;"></div>
              ${barHtml}
            </div>
          </div>
        `;
            };
            setHtml('#stats-grid', `
        <div style="display:grid; grid-template-columns:1fr 1fr; gap:12px;">
          <div>${renderStat('war', 'Võ Lực', stats['Võ Lực'])}${renderStat('cmd', 'Thống Soái', stats['Thống Soái'])}${renderStat('theo', 'Thần Học', stats['Thần Học'])}</div>
