        </div>
      `);

            const rel = _.get(vars, 'Mối Quan Hệ', {});
            const renderCharList = (dict, listId) => {
                const html = Object.entries(dict || {}).map(([k, v]) => {
                    const details = encodeURIComponent(JSON.stringify(v));
                    return `
