              <div style="display:flex;justify-content:space-between;">
                <span><b>${k}</b> <span style="font-size:10px;color:#736453;">(${v['Chức Vụ'] || 'Không có chức vụ'})</span></span>
                <span style="color:var(--wax-red);font-weight:bold;">${v['Độ Hảo Cảm'] !== undefined ? v['Độ Hảo Cảm'] : '?'}</span>
              </div>
            </div>`;
                }).join('');
                setHtml(listId, html || '<div class="list-item" style="text-align:center; color:#736453; font-style:italic;"> Không có hồ sơ nhân sự</div>');
            };

            renderCharList(rel['Nhân Mạch Cốt Lõi'], '#list-core-rel');
