            /* ========================== Phân tích dữ liệu chế độ lính đánh thuê ========================== */

            const merc = _.get(vars, 'Đoàn Lính Đánh Thuê', {});

            /* Trích xuất riêng: Thống soái và thời cuộc */
            setText('#m-player-name', _.get(player, ['Hồ Sơ Gia Tộc', 'Tên'], 'Chưa có tên'));
            setText('#m-player-age', _.get(player, ['Hồ Sơ Gia Tộc', 'Tuổi'], '?'));
            setText('#m-year', _.get(world, ['Thời Gian', 'Năm']));
            setText('#m-cal', calRaw.split(/[\/|]/)[0]);
            setText('#m-sit', world['Tình Hình Hiện Tại'] || 'Sóng yên biển lặng');
            setText('#m-dil', world['Khó Khăn Hiện Tại'] || 'Tạm không có khủng hoảng');

            /* Thông tin doanh trại quân đoàn phần đầu */
            setText('#m-name', _.get(merc, ['Tổng Quan', 'Tên Quân Đoàn'], 'Đoàn Lính Đánh Thuê Chữ Thập Đen'));
            setText('#m-motto', '"' + _.get(merc, ['Tổng Quan', 'Tôn Chỉ Quân Đoàn'], 'Bạc Là Lòng Trung Thành') + '"');

            // Trích xuất thẻ tổng quân đoàn hoàn chỉnh
            const mainTroopHtml = `
        <div class="list-item" style="background:rgba(139,28,28,0.03); padding:8px; border:1px solid rgba(139,28,28,0.3); margin-bottom:10px; border-radius:2px;">
          <div style="display:flex;justify-content:space-between;border-bottom:1px dashed rgba(139,28,28,0.3);padding-bottom:4px;margin-bottom:4px;">
            <b style="color:var(--wax-red);">⚔ Tổng quân đoàn (Bộ đội chủ lực)</b>
