          </div>
          <div style="display:grid; grid-template-columns:1fr 1fr; font-size:11px; gap:6px; color:#5a5045;">
            <span> Chỉ huy: <b style="color:var(--ink-black);">${_.get(merc, ['Tổng Quan', 'Chỉ Huy'], 'Tạm Khuyết')}</b></span>
            <span> Binh Chủng: ${_.get(merc, ['Tổng Quan', 'Binh Chủng'], 'Chưa rõ')}</span>
            <span> Sĩ Khí: <span class="badge ${determineStatusColor(_.get(merc, ['Tổng Quan', 'Sĩ Khí'], ''), 'Sĩ Khí')}">${_.get(merc, ['Tổng Quan', 'Sĩ Khí'], 'Chưa rõ')}</span></span>
            <span> Huấn Luyện: <span class="badge ${determineStatusColor(_.get(merc, ['Tổng Quan', 'Huấn Luyện'], ''), 'Huấn Luyện')}">${_.get(merc, ['Tổng Quan', 'Huấn Luyện'], 'Chưa rõ')}</span></span>
            <span> Trang Bị: ${_.get(merc, ['Tổng Quan', 'Trang Bị'], 'Chưa rõ')}</span>
            <span> Hậu Cần: <span class="badge ${determineStatusColor(_.get(merc, ['Tổng Quan', 'Tình Trạng Hậu Cần'], ''), 'Hậu Cần')}">${_.get(merc, ['Tổng Quan', 'Tình Trạng Hậu Cần'], 'Chưa rõ')}</span></span>
          </div>
          <div style="font-size:11px; margin-top:6px; color:var(--wax-red);"> Nơi Đồn Trú: ${_.get(merc, ['Tổng Quan', 'Nơi Đồn Trú Hiện Tại'], 'Chưa rõ')} | Động Thái: ${_.get(merc, ['Tổng Quan', 'Động Thái'], 'Chờ Lệnh')}</div>
          <div style="font-size:11px; margin-top:3px; color:#736453; font-style:italic; padding-top:4px; border-top:1px dotted rgba(166,138,86,0.3);"> Giải Thích: ${_.get(merc, ['Tổng Quan', 'Giải Thích'], 'Không')}</div>
        </div>
      `;
            setHtml('#main-troop-container', mainTroopHtml);

            // Phân tích bộ đội ngoại vi trực thuộc
            const subTroops = _.get(merc, 'Bộ Đội Trực Thuộc', {});
            const subTroopsHtml = Object.entries(subTroops).map(([k, v]) => `
        <div class="list-item" style="background:rgba(0,0,0,0.02); padding:8px; border:1px solid rgba(166,138,86,0.3); margin-bottom:6px; border-radius:2px;">
          <div style="display:flex;justify-content:space-between;border-bottom:1px dashed rgba(166,138,86,0.3);padding-bottom:4px;margin-bottom:4px;">
            <b style="color:var(--ink-black);">${k}</b>
            <b style="color:var(--wax-red);">${v['Binh Lực'] || 0} Người</b>
          </div>
          <div style="display:grid; grid-template-columns:1fr 1fr; font-size:11px; gap:4px; color:#5a5045;">
            <span> Chỉ huy: ${v['Chỉ Huy Bộ Đội'] || 'Tạm Khuyết'}</span>
            <span> Binh Chủng: ${v['Binh Chủng'] || 'Chưa rõ'}</span>
            <span> Sĩ Khí: <span class="badge ${determineStatusColor(v['Sĩ Khí'], 'Sĩ Khí')}">${v['Sĩ Khí'] || 'Chưa rõ'}</span></span>
            <span> Hậu Cần: <span class="badge ${determineStatusColor(v['Tình Trạng Hậu Cần'], 'Hậu Cần')}">${v['Tình Trạng Hậu Cần'] || 'Chưa rõ'}</span></span>
          </div>
          <div style="font-size:11px; margin-top:4px; color:var(--wax-red);"> Nơi Đồn Trú: ${v['Nơi Đồn Trú'] || 'Chưa rõ'} | Động Thái: ${v['Động Thái'] || 'Chờ Lệnh'}</div>
          <div style="font-size:11px; margin-top:2px; color:#736453; font-style:italic;"> Giải Thích: ${v['Giải Thích'] || 'Không'}</div>
        </div>
      `).join('');
            setHtml('#list-sub-troops', subTroopsHtml || '<div class="list-item" style="text-align:center;"> Tạm không có bộ đội ngoại vi trực thuộc</div>');

            // Phần kinh tế
            const vault = _.get(merc, ['Kinh Tế', 'Số Dư Kho Bạc'], '0 Thaler');
            const income = _.get(merc, ['Kinh Tế', 'Thu Nhập Dự Kiến Tháng Này'], '0 Thaler');
            const expense = _.get(merc, ['Kinh Tế', 'Chi Phí Dự Kiến Tháng Này'], '0 Thaler');

            setHtml('#m-vault', `<span style="color:var(--wax-red); font-family:\'Cinzel\',serif; font-size:16px;">${vault}</span>`);
            setText('#m-income', income);
            setText('#m-expense', expense);

            /* Khoản nợ đã có hiệu lực (Lịch sử vay mượn)) */
            const loans = _.get(merc, 'Lịch Sử Vay Mượn', {});
            const loansHtml = Object.entries(loans).map(([k, v]) => `
        <div class="list-item" style="border:1px solid #d19e9e; background:rgba(163,38,38,0.05); padding:6px; margin-bottom:4px; border-radius:2px;">
          <div style="display:flex; justify-content:space-between; margin-bottom:2px;">
            <b style="color:var(--status-bad);">${k}</b>
            <span style="font-size:11px; color:var(--ink-black);"> Vay mượn: <b style="color:var(--wax-red);">${v['Số Tiền Vay']}</b> | Tiền Lãi: ${v['Tiền Lãi']}</span>
          </div>
          <div style="font-size:11px; color:#5a5045;"> Chủ nợ: ${v['Bên Vay Mượn']} | Thời hạn: ${v['Thời Hạn']}</div>
          <div style="font-size:11px; color:#736453; margin-top:2px;"> Điều khoản: ${v['Yêu Cầu Vay Mượn']}</div>
          ${v['Giải Thích'] ? `<div style="font-size:10px; color:#a32626; margin-top:3px; font-style:italic;"> Chú thích: ${v['Giải Thích']}</div>` : ''}
        </div>
      `).join('');
            setHtml('#list-loans', loansHtml || '<div class="list-item" style="text-align:center;"> Tạm không có khoản nợ</div>');

            /* Nhân sự giao thiệp đồn trú */
            const localNpcs = _.get(vars, 'Nhân Sự Đồn Trú', {});
            const npcsHtml = Object.entries(localNpcs).map(([k, v]) => {
                const name = v['Họ Tên'] || 'Chưa có tên';
                const job = v['Chức Trách'] || k;
                const fav = v['Độ Hảo Cảm'] !== undefined ? v['Độ Hảo Cảm'] : '0';
                return `
          <div class="list-item" style="display:flex; justify-content:space-between; align-items:center;">
            <div onclick="openNpcModal('${k}')" style="cursor:pointer; flex:1;">
              <b class="clickable-npc-name">🏛 ${job}</b><br>
              <span style="font-size:10px;color:#736453;">${name} | Hảo cảm: <span style="color:var(--wax-red);">${fav}</span></span>
            </div>
            <div style="display:flex; gap:6px;">
              <button class="action-btn" onclick="handleAction('Giao thiệp', 'Gặp mặt ${job}(Trò chuyện)')"> Trò chuyện</button>
              <button class="action-btn urgent" onclick="handleAction('Giao thiệp', 'Hối lộ ${job}')"> Hối lộ</button>
            </div>
          </div>
        `;
            }).join('');
            setHtml('#list-local-npcs', npcsHtml || '<div class="list-item" style="text-align:center;"> Tạm không có hồ sơ nhân sự giao thiệp đồn trú</div>');

            /* Hợp Đồng Hiện Tại */
            const activeContracts = _.get(merc, 'Hợp Đồng Hiện Tại', {});
            const activeContractsHtml = Object.entries(activeContracts).map(([k, v]) => `
        <div class="list-item" style="border:1px solid rgba(42, 106, 59, 0.4); background:rgba(42, 106, 59, 0.05); padding:8px; margin-bottom:6px; border-radius:2px;">
          <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:4px;">
            <b style="color:var(--ink-black);">${k}</b>
            <span class="badge badge-good"> Đang thực hiện</span>
          </div>
          <div style="font-size:11px; color:#5a5045;">
            <b> Người thuê:</b> ${v['Bên Ủy Thác'] || 'Chưa rõ'} | <b> Tiền thưởng:</b> <span style="color:var(--wax-red);">${v['Tiền Thưởng'] || 'Chưa rõ'}</span> | <b> Thời hạn:</b> ${v['Thời Hạn'] || 'Không'}
          </div>
          <div style="font-size:11px; color:#5a5045; margin-top:4px;"><b> Yêu cầu khế ước:</b> ${v['Yêu Cầu Đơn Hàng'] || v['Giải Thích'] || 'Không'}</div>
        </div>
      `).join('');
            setHtml('#list-contracts', activeContractsHtml || '<div class="list-item" style="text-align:center;"> Tạm không có nhiệm vụ đang thực hiện</div>');

            bindEvents();
        }

        function bindEvents() {
            /* Mở rộng thu gọn bảng điều khiển */
            $('.section-header').off('click').on('click', function() {
                $(this).toggleClass('collapsed');
            });

            /* Tự do Tab Chuyển đổi */
            $('.mode-tab').off('click').on('click', function() {
                $('.mode-tab').removeClass('active');
                $(this).addClass('active');

                const targetMode = $(this).data('mode');
                $('.mode-container').removeClass('active');
                $('#' + targetMode).addClass('active');
            });

            /* Nhân Mạch Cốt Lõi/Cửa sổ chi tiết thẻ cận thần */
            $('.char-item').off('click').on('click', function() {
                const name = $(this).data('name');
                const data = JSON.parse(decodeURIComponent($(this).data('details')));

                $('#m-name-modal').text(name);
                $('#m-job-modal').text(data['Chức Vụ'] || 'Không có danh hiệu');

                $('#m-age-container').show();
                $('#m-age-modal').text(data['Tuổi'] ? `${data['Tuổi']} Tuổi` : 'Chưa rõ');
                $('#m-fav-modal').text(data['Độ Hảo Cảm'] !== undefined ? data['Độ Hảo Cảm'] : '0');

                if (data['Số Lần Quan Hệ'] !== undefined) {
                    $('#m-sex-container').show();
                    $('#m-sex').text(data['Số Lần Quan Hệ']);
                } else {
                    $('#m-sex-container').hide();
                }

                const getAttrHtml = (val) => {
                    const n = Number(val) || 0;
                    const color = n >= 0 ? 'var(--status-good)' : 'var(--status-bad)';
                    return `<span class="modal-attr-val" style="color:${color};">${n > 0 ? '+' : ''}${n}</span>`;
                };

                if (data['Võ Lực'] !== undefined) {
                    $('#m-attrs-container').show();
                    $('#m-war').html(getAttrHtml(data['Võ Lực']));
                    $('#m-cmd').html(getAttrHtml(data['Thống Soái']));
                    $('#m-theo').html(getAttrHtml(data['Thần Học']));
                    $('#m-plot').html(getAttrHtml(data['Âm Mưu']));
                    $('#m-fin').html(getAttrHtml(data['Tài Chính']));
                    $('#m-dip').html(getAttrHtml(data['Ngoại Giao']));
                } else {
                    $('#m-attrs-container').hide();
                }

                $('#m-eval').text(data['Đánh Giá'] || 'Tạm không có đánh giá');
                $('#m-desc').text(data['Giải Thích'] || 'Không có hồ sơ giải thích');

                openModal('char-modal');
            });

            /* Đóng cửa sổ */
            $('.modal-close, .modal-overlay').off('click').on('click', function(e) {
                if (e.target === this) $('.modal-overlay').fadeOut(150);
            });
        }

        async function init() {
            await waitGlobalInitialized('Mvu');
            populateData();
            eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, populateData);
        }

        $(errorCatched(init));
    </script>
</head>

