            padding: 0;
            box-sizing: border-box;
        }

        body {
            /* Tawa đã đồng bộ font chữ sang phong cách cổ điển */
            font-family: "Georgia", "Times New Roman", serif;
            background: transparent;
            padding: 8px;
            color: #2c241b;
        }

        .board-container {
            max-width: 500px;
            margin: 10px auto;
