        </div>
    </div>

    <script>
        /* ========== Lấy nội dung tin nhắn ========== */
        function getMessageData() {
            var chatMessages = getChatMessages(getCurrentMessageId());
            if (!chatMessages || chatMessages.length === 0) {
                console.error("Không thể lấy nội dung tin nhắn");
                return null;
            }
            return chatMessages[0].message;
        }

        /* ========== Phân tích dữ liệu ========== */
        function parseData(messageText) {
            var result = {
                loans: []
            };

            /* Trích xuất nội dung thẻ */
            var tagMatch = messageText.match(/<bank_loans>([\s\S]*?)<\/bank_loans>/);
            if (!tagMatch || !tagMatch[1]) {
                console.error("Không tìm thấy nội dung thẻ");
                return result;
            }

            var content = tagMatch[1];

            /* Dùng --- làm đường phân cách để chia dữ liệu của các ngân hàng khác nhau */
            var sections = content.split('---');

            sections.forEach(function(section) {
                var trimmedSection = section.trim();
                if (!trimmedSection) return;

                var loan = {};
                var regex = /\[([^\|]+)\|([^\]]+)\]/g;
                var match;

                while ((match = regex.exec(trimmedSection)) !== null) {
                    var key = match[1].trim();
                    var value = match[2].trim();
                    loan[key] = value;
                }

                if (Object.keys(loan).length > 0) {
                    result.loans.push(loan);
                }
            });

            return result;
        }

        /* ========== Hàm tương tác ========== */
        window.handleClick = function(action, loanName) {
            if (typeof triggerSlash === 'function') {
                /* Tawa đã thêm ngoặc vuông và khoảng trắng | /trigger để AI phản hồi tự động chuẩn nhất */
                var cmd = '/send ' + action + ': 【' + loanName + '】';
                triggerSlash(cmd + ' | /trigger');
            }
        };

        /* ========== Hiển thị giao diện ========== */
        function renderPage(data) {
            if (!data.loans || data.loans.length === 0) {
                document.getElementById('content').innerHTML = '<div class="loading"> Không tìm thấy phương án vay mượn khả dụng, vui lòng đảm bảo AI xuất ra theo đúng định dạng.</div>';
                return;
            }

            var html = '';

            data.loans.forEach(function(loan) {
                var title = loan['Tên Khoản Vay'] || 'Khoản vay chưa đặt tên';
                var provider = loan['Bên Vay Mượn'] || 'Chủ tài trợ chưa rõ';
                var amount = loan['Số Tiền Vay'] || '0';
                var interest = loan['Tiền Lãi'] || 'Chưa rõ';
                var timeLimit = loan['Thời Hạn'] || 'Chưa rõ';
                var requirement = loan['Yêu Cầu Vay Mượn'] || 'Không có yêu cầu đặc biệt';
                var desc = loan['Giải Thích'] || 'Không có giải thích bổ sung.';

                /* Tawa đã lắp khiên bảo vệ chống sập HTML bằng replace nháy đơn và kép */
                var safeTitle = title.replace(/'/g, "\\'").replace(/"/g, "&quot;");

                html += '<div class="loan-card">';
                html += '    <div class="loan-title">';
                html += '        <span>' + provider + '</span>';
                html += '        <span class="loan-amount">' + amount + ' Thaler</span>';
                html += '    </div>';
                html += '    <div class="info-grid">';
                html += '        <div class="info-item"><span class="info-label"> Tên Khoản Vay:</span><span class="info-value">' + title + '</span></div>';
                html += '        <div class="info-item"><span class="info-label"> Tiền Lãi:</span><span class="info-value" style="color: #8b1c1c;">' + interest + '</span></div>';
                html += '        <div class="info-item"><span class="info-label"> Thời hạn trả nợ:</span><span class="info-value">' + timeLimit + '</span></div>';
                html += '        <div class="info-item"><span class="info-label"> Thế chấp/Yêu cầu:</span><span class="info-value">' + requirement + '</span></div>';
                html += '    </div>';
                html += '    <div class="loan-desc">' + desc + '</div>';
                html += '    <div class="btn-group">';
                html += '        <button class="action-btn btn-accept" onclick="handleClick(\'Chấp nhận khoản vay\', \'' + safeTitle + '\')"> Ký kết khế ước (Chấp nhận)</button>';
                html += '        <button class="action-btn btn-reject" onclick="handleClick(\'Từ chối khoản vay\', \'' + safeTitle + '\')"> Phất tay bỏ đi (Từ chối)</button>';
                html += '    </div>';
                html += '</div>';
            });

            document.getElementById('content').innerHTML = html;
        }

        /* ========== Hàm chính ========== */
        function init() {
            try {
                var messageText = getMessageData();
                if (!messageText) {
                    document.getElementById('content').innerHTML = '<div class="loading">❌ Không thể lấy nội dung tin nhắn</div>';
                    return;
                }
                var data = parseData(messageText);
                renderPage(data);
            } catch (error) {
                console.error("Lỗi:", error);
                document.getElementById('content').innerHTML = '<div class="loading">❌ Tải thất bại:' + error.message + '</div>';
            }
        }

        $(function() {
            init();
        });
    </script>
</body>

</html>
