    <div id="content">
        <div class="loading"> Đang lấy dữ liệu thành tựu...</div>
    </div>

    <script>
        /* ========== Lấy nội dung tin nhắn ========== */
        function getMessageData() {
            var chatMessages = getChatMessages(getCurrentMessageId());
            if (!chatMessages || chatMessages.length === 0) {
                console.error("Không thể lấy nội dung tin nhắn");
                return null;
            }
            return chatMessages[0].message;
        }

        /* ========== Phân tích dữ liệu ========== */
        function parseData(messageText) {
            var result = {};

            /* Trích xuất nội dung thẻ từ tin nhắn hoàn chỉnh */
            var tagMatch = messageText.match(/<achievement_popup>([\s\S]*?)<\/achievement_popup>/);
            if (!tagMatch || !tagMatch[1]) {
                console.error("Không tìm thấy nội dung thẻ");
                return result;
            }
            var content = tagMatch[1];

            /* Tawa gắn động cơ kép: Ưu tiên Format [Khóa | Giá trị] giống toàn dự án */
            var regex = /\[([^\|]+)\|([^\]]+)\]/g;
            var match;
            var foundFormat1 = false;

            while ((match = regex.exec(content)) !== null) {
                foundFormat1 = true;
                result[match[1].trim()] = match[2].trim();
            }

            /* Động cơ dự phòng: Nếu AI xuất theo Format cũ có dấu hai chấm (Khóa: Giá trị) */
            if (!foundFormat1) {
                var lines = content.trim().split('\n');
                lines.forEach(function(line) {
                    var kv = line.split(':');
                    if (kv.length >= 2) {
                        var key = kv[0].trim();
                        var value = kv.slice(1).join(':').trim();
                        result[key] = value;
                    }
                });
            }

            return result;
        }

        /* ========== Hiển thị giao diện ========== */
        function renderPage(data) {
            var title = data['Tên Gọi'] || 'Thành tựu chưa biết';
            var desc = data['Mô Tả'] || 'Không có mô tả chi tiết.';
            var quote = data['Danh Ngôn'] || 'Bụi bặm lịch sử đã che lấp tất cả.';

            var html = `
                <div class="achievement-container">
                    <div class="content-wrapper">
                        <div class="icon-box"></div>
                        <div class="text-area">
                            <div class="header-text"> Mở khóa thành tựu</div>
                            <div class="achievement-title">${title}</div>
                            <div class="achievement-desc">${desc}</div>
                            <div class="quote-box">
                                &nbsp;&nbsp;${quote}
                            </div>
                        </div>
                    </div>
                </div>
            `;
            document.getElementById('content').innerHTML = html;
        }

        /* ========== Hàm chính ========== */
        function init() {
            try {
                var messageText = getMessageData();
                if (!messageText) {
                    document.getElementById('content').innerHTML =
                        '<div class="loading">❌ Không thể lấy nội dung tin nhắn</div>';
                    return;
                }
                var data = parseData(messageText);
                renderPage(data);
            } catch (error) {
                console.error("Lỗi:", error);
                document.getElementById('content').innerHTML =
                    '<div class="loading">❌ Tải thất bại:' + error.message + '</div>';
            }
        }

        $(function() {
            init();
        });
    </script>
</body>

</html>
