<body>
    <div id="content">
        <div class="loading"> Đang kéo bức màn đỏ sẫm lên...</div>
    </div>

    <script>
        /* ========== Lấy nội dung tin nhắn ========== */
        function getMessageData() {
            var chatMessages = getChatMessages(getCurrentMessageId());
            if (!chatMessages || chatMessages.length === 0) {
                console.error("Không thể lấy nội dung tin nhắn");
                return null;
            }
            return chatMessages[0].message;
        }

        /* ========== Hàm xử lý từng cặp Khóa - Giá trị ========== */
        function processKeyValue(key, value, result) {
            if (key === 'Tiêu Đề') {
                result.title = value;
            } else if (key === 'Mô Tả') {
                result.description = value;
            } else if (key.indexOf('Tùy chọn') !== -1 && key !== 'Tùy Chọn Đặc Biệt') {
                /* Cho phép gạch nối - hoặc gạch dài — làm dải phân cách */
                var sepMatch = value.match(/[-—]/);
                if (sepMatch) {
                    var dashIndex = value.indexOf(sepMatch[0]);
                    result.options.push({
                        id: key,
                        name: value.substring(0, dashIndex).trim(),
                        desc: value.substring(dashIndex + 1).trim()
                    });
                } else {
                    result.options.push({
                        id: key,
                        name: value,
                        desc: ''
                    });
                }
            } else if (key === 'Tùy Chọn Đặc Biệt') {
                var sepMatch = value.match(/[-—]/);
                if (sepMatch) {
                    var dashIndex = value.indexOf(sepMatch[0]);
                    result.specialOption = {
                        name: value.substring(0, dashIndex).trim(),
                        desc: value.substring(dashIndex + 1).trim()
                    };
                } else {
                    result.specialOption = {
                        name: 'Tình huống bất thường',
                        desc: value
                    };
                }
            }
        }

        /* ========== Phân tích dữ liệu ========== */
        function parseData(messageText) {
            var result = {
                title: 'Chốn phong nguyệt',
                description: '',
                options: [],
                specialOption: null
            };

            var tagMatch = messageText.match(/<brothel_event>([\s\S]*?)<\/brothel_event>/);
            if (!tagMatch || !tagMatch[1]) {
                console.error("Không tìm thấy nội dung thẻ");
                return result;
            }
            var content = tagMatch[1].trim();

            /* Tawa gắn Động Cơ Kép chống mù dữ liệu do sai format AI */
            var regex = /\[([^\|]+)\|([^\]]+)\]/g;
            var match;
            var foundFormat1 = false;

            while ((match = regex.exec(content)) !== null) {
                foundFormat1 = true;
                processKeyValue(match[1].trim(), match[2].trim(), result);
            }

            /* Động cơ 2: Nếu AI không xuất dạng [] mà xuất dạng Khóa: Giá Trị */
            if (!foundFormat1) {
                var lines = content.split('\n');
                lines.forEach(function(line) {
                    var separatorIndex = line.indexOf(':');
                    if (separatorIndex !== -1) {
                        var key = line.substring(0, separatorIndex).trim();
                        var value = line.substring(separatorIndex + 1).trim();
                        processKeyValue(key, value, result);
                    }
                });
            }

            return result;
        }

        /* ========== Gửi lệnh tương tác ========== */
        function handleClick(optionName) {
            if (typeof triggerSlash === 'function') {
                /* Tawa thêm ngoặc vuông và khoảng trắng chuẩn SillyTavern */
                triggerSlash('/send Quyết định tại chốn phong nguyệt: 【' + optionName + '】 | /trigger');
            }
        }

        /* ========== Render giao diện ========== */
        function renderPage(data) {
            var html = '<div class="brothel-container">';

            /* Tiêu đề và mô tả */
            html += '<div class="title">' + (data.title || 'Nơi chưa rõ') + '</div>';
            html += '<div class="description">' + (data.description || 'Những lời thì thầm tràn ngập trong góc tối.') + '</div>';

            /* Danh sách tùy chọn thông thường */
            if (data.options && data.options.length > 0) {
                html += '<div class="options-list">';
                data.options.forEach(function(opt) {
                    /* Tawa gắn khiên chống sập HTML do dấu nháy */
                    var safeName = opt.name.replace(/'/g, "\\'").replace(/"/g, "&quot;");
                    html += `
                        <div class="option-btn" onclick="handleClick('${safeName}')">
                            <div class="opt-name">${opt.name}</div>
                            <div class="opt-desc">${opt.desc}</div>
                        </div>
                    `;
                });
                html += '</div>';
            }

            /* Tùy Chọn Đặc Biệt */
            if (data.specialOption) {
                var safeSpName = data.specialOption.name.replace(/'/g, "\\'").replace(/"/g, "&quot;");
                html += `
                    <div class="special-option-box">
                        <div class="special-btn" onclick="handleClick('${safeSpName}')">
                            <div class="sp-label">◆ Phát hiện bất thường ◆</div>
                            <div class="opt-name">${data.specialOption.name}</div>
                            <div class="sp-desc">${data.specialOption.desc}</div>
                        </div>
                    </div>
                `;
            }

            html += '</div>';
            document.getElementById('content').innerHTML = html;
        }

        /* ========== Hàm chính ========== */
        function init() {
            try {
                var messageText = getMessageData();
                if (!messageText) {
                    document.getElementById('content').innerHTML =
                        '<div class="loading">❌ Không thể lấy nội dung tin nhắn</div>';
                    return;
                }
                var data = parseData(messageText);
                renderPage(data);
            } catch (error) {
                console.error("Lỗi:", error);
                document.getElementById('content').innerHTML =
                    '<div class="loading">❌ Tải thất bại:' + error.message + '</div>';
            }
        }

        $(function() {
            init();
        });
    </script>
</body>

</html>
