        'Thống Soái': z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
        'Thần Học': z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
        'Âm Mưu': z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
        'Tài Chính': z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
        'Ngoại Giao': z.coerce.number().transform(v => _.clamp(v, -100, 100)).prefault(0),
      })
    ).prefault({}),
    'Hậu Đình': z.record(
      safeString().describe('Họ Tên'),
      z.object({
        'Tuổi': z.coerce.number(),
        'Chức Vụ': safeString(),
        'Độ Hảo Cảm': z.coerce.number().transform(v => _.clamp(v, -100, 100)),
        'Đánh Giá': safeString(),
        'Số Lần Quan Hệ': z.coerce.number().prefault(0),
        'Giải Thích': safeString(),
      })
    ).prefault({}),
    'Động Thái Gia Tộc': safeString().prefault('Các nhánh gia tộc hiện duy trì sự hòa thuận bề ngoài.'),
    'Động Thái Hậu Cung': safeString().prefault('Không Ai Tranh Sủng'),
  }),

  'Thái Độ Thế Lực': z.object({
    'Đánh Giá Quốc Gia': z.record(
      safeString().describe('Tên Quốc Gia'),
      z.object({
        'Thái Độ': z.enum(['Tín nhiệm', 'Ủng hộ', 'Cuồng Nhiệt', 'Cảnh giác', 'Dao động', 'Bất mãn', 'Địch ý', 'Căm hận', 'Nổi loạn']).prefault('Cảnh giác'),
        'Mô Tả Cụ Thể': safeString()
      })
    ).prefault({}),

    'Đánh Giá Tôn Giáo': z.record(
      safeString().describe('Tên Giáo Phái/Tòa Thánh'),
      z.object({
        'Thái Độ': z.enum(['Tín nhiệm', 'Ủng hộ', 'Cuồng Nhiệt', 'Cảnh giác', 'Dao động', 'Bất mãn', 'Địch ý', 'Căm hận', 'Nổi loạn']).prefault('Cảnh giác'),
        'Mô Tả Cụ Thể': safeString()
      })
    ).prefault({}),

    'Đánh Giá Giai Cấp': z.record(
      safeString().describe('Tên Giai Cấp'),
      z.object({
        'Thái Độ': z.enum(['Tín nhiệm', 'Ủng hộ', 'Cuồng Nhiệt', 'Cảnh giác', 'Dao động', 'Bất mãn', 'Địch ý', 'Căm hận', 'Nổi loạn']).prefault('Cảnh giác'),
        'Mô Tả Cụ Thể': safeString()
      })
    ).prefault({})
  }),

  'Nhân Sự Đồn Trú': z.record(
    safeString().describe('Chức vụ hoặc loại, ví dụ: Trưởng quan đồn trú, đại diện ngân hàng'),
    z.object({
      'Họ Tên': safeString(),
      'Chức Trách': safeString(),
      'Độ Hảo Cảm': z.coerce.number().transform(v => _.clamp(v, -100, 100)),
      'Đánh Giá': safeString(),
      'Giải Thích': safeString(),
    })
  ).prefault({}),

  'Tài Sản Và Danh Tiếng': z.object({
    'Sản Nghiệp': z.record(
      safeString().describe('Tên sản nghiệp'),
      z.object({
        'Tình Hình Thu Chi': safeString().describe('Thu chi cụ thể, không giới hạn tiền tệ'),
        'Trạng Thái Hoạt Động': safeString(),
      })
    ).prefault({}),
    'Vật Tư Dự Trữ': z.record(
      safeString().describe('Tên vật tư dự trữ'),
      z.object({
        'Số Lượng': safeString().describe('Mô tả số lượng cụ thể'),
        'Giải Thích': safeString(),
      })
    ).prefault({}),
    'Danh Dự': z.record(
      safeString().describe('Tên Gọi'),
      safeString().describe('Mô Tả Cụ Thể')
    ).prefault({}),
  }),

  'Biên Chế Quân Sự': z.object({
    'Bộ Đội': z.record(
      safeString().describe('Tên bộ đội'),
      z.object({
        'Tướng Lĩnh': safeString().prefault('Tạm Khuyết'),
        'Số Lượng': z.coerce.number(),
        'Tình Trạng Hậu Cần': z.enum(['Tiếp Tế Dồi Dào', 'Cố Gắng Cầm Cự', 'Cực Kỳ Thiếu Thốn']).prefault('Cố Gắng Cầm Cự'),
        'Sĩ Khí': z.enum(['Cuồng Nhiệt', 'Ổn Định', 'Vô Cảm', 'Kích Động', 'Binh Biến']).prefault('Ổn Định'),
        'Trang Bị': z.enum(['Trọng Giáp Tinh Nhuệ', 'Đồng Bộ Chỉnh Tề', 'Chế Tạo Thô Sơ']).prefault('Đồng Bộ Chỉnh Tề'),
        'Huấn Luyện': z.enum(['Tinh Nhuệ Hoàn Hảo', 'Hoạt Động Trơn Tru', 'Mới Thành Đội Hình', 'Rời Rạc Vô Trật Tự']).prefault('Mới Thành Đội Hình'),
        'Động Thái Bộ Đội': safeString(),
        'Giải Thích': safeString(),
      })
    ).prefault({})
  }),

  'Hải Quân': z.object({
    'Hạm Đội': z.record(
      safeString().describe('Tên hạm đội'),
      z.object({
        'Loại Hạm Đội': safeString(),
        'Số Lượng Hạm Đội': safeString(),
        'Sĩ Khí Hạm Đội': z.enum(['Cuồng Nhiệt', 'Ổn Định', 'Vô Cảm', 'Kích Động', 'Binh Biến']).prefault('Ổn Định'),
        'Tình Trạng Hậu Cần': z.enum(['Tiếp Tế Dồi Dào', 'Cố Gắng Cầm Cự', 'Cực Kỳ Thiếu Thốn']).prefault('Cố Gắng Cầm Cự'),
        'Động Thái Hạm Đội': safeString(),
        'Cảng Đồn Trú Hạm Đội': safeString(),
        'Chỉ Huy Hạm Đội': safeString(),
        'Đánh Giá Hạm Đội': safeString(),
        'Soái Hạm': z.object({
          'Tên Kỳ Hạm': safeString().prefault('Tạm Không Có'),
          'Loại Kỳ Hạm': safeString().prefault('Tạm Không Có'),
          'Giải Thích Kỳ Hạm': safeString().prefault('Tạm Không Có'),
          'Tình Trạng Kỳ Hạm': safeString().prefault('Tạm Không Có'),
          'Chỉ Huy Kỳ Hạm': safeString().prefault('Tạm Không Có'),
        }).prefault({}),
      })
    ).prefault({})
  }),

  'Đoàn Lính Đánh Thuê': z.object({
    'Tổng Quan': z.object({
      'Tên Quân Đoàn': safeString().prefault('Đoàn Lính Đánh Thuê Chữ Thập Đen'),
      'Tôn Chỉ Quân Đoàn': safeString().prefault('Bạc Là Lòng Trung Thành'),
      'Chỉ Huy': safeString().prefault('Đại Úy'),
      'Tổng Binh Lực': z.coerce.number().prefault(300),
      'Nơi Đồn Trú Hiện Tại': safeString().prefault('Doanh Trại Chưa Rõ'),
      'Sĩ Khí': z.enum(['Cuồng Nhiệt', 'Ổn Định', 'Vô Cảm', 'Kích Động', 'Binh Biến']).prefault('Vô Cảm'),
      'Huấn Luyện': z.enum(['Tinh Nhuệ Hoàn Hảo', 'Hoạt Động Trơn Tru', 'Mới Thành Đội Hình', 'Rời Rạc Vô Trật Tự']).prefault('Mới Thành Đội Hình'),
      'Trang Bị': z.enum(['Trọng Giáp Tinh Nhuệ', 'Đồng Bộ Chỉnh Tề', 'Chế Tạo Thô Sơ']).prefault('Đồng Bộ Chỉnh Tề'),
      'Tình Trạng Hậu Cần': z.enum(['Tiếp Tế Dồi Dào', 'Cố Gắng Cầm Cự', 'Cực Kỳ Thiếu Thốn']).prefault('Cố Gắng Cầm Cự'),
      'Binh Chủng': safeString().prefault('Hỗn Hợp Lính Giáo Và Súng Hỏa Mai'),
      'Động Thái': safeString().prefault('Chờ Lệnh'),
      'Giải Thích': safeString().prefault('Trạng Thái Tổng Quan Quân Đoàn.'),
    }),
    'Bộ Đội Trực Thuộc': z.record(
      safeString().describe('Tên phân đội'),
      z.object({
        'Chỉ Huy Bộ Đội': safeString(),
        'Binh Lực': z.coerce.number(),
        'Nơi Đồn Trú': safeString(),
        'Sĩ Khí': z.enum(['Cuồng Nhiệt', 'Ổn Định', 'Vô Cảm', 'Kích Động', 'Binh Biến']).prefault('Ổn Định'),
        'Huấn Luyện': z.enum(['Tinh Nhuệ Hoàn Hảo', 'Hoạt Động Trơn Tru', 'Mới Thành Đội Hình', 'Rời Rạc Vô Trật Tự']).prefault('Mới Thành Đội Hình'),
        'Trang Bị': z.enum(['Trọng Giáp Tinh Nhuệ', 'Đồng Bộ Chỉnh Tề', 'Chế Tạo Thô Sơ']).prefault('Đồng Bộ Chỉnh Tề'),
        'Tình Trạng Hậu Cần': z.enum(['Tiếp Tế Dồi Dào', 'Cố Gắng Cầm Cự', 'Cực Kỳ Thiếu Thốn']).prefault('Cố Gắng Cầm Cự'),
        'Binh Chủng': safeString(),
        'Động Thái': safeString(),
        'Giải Thích': safeString(),
      })
    ).prefault({}),
    'Kinh Tế': z.object({
      'Số Dư Kho Bạc': safeString().prefault('0 Thaler'),
      'Thu Nhập Dự Kiến Tháng Này': safeString().prefault('0 Thaler'),
      'Chi Phí Dự Kiến Tháng Này': safeString().prefault('0 Thaler'),
    }),
    'Lịch Sử Vay Mượn': z.record(
      safeString().describe('Tên Khoản Vay'),
      z.object({
        'Bên Vay Mượn': safeString(),
        'Thời Hạn': safeString(),
        'Yêu Cầu Vay Mượn': safeString(),
        'Số Tiền Vay': z.coerce.number(),
        'Tiền Lãi': safeString(),
        'Giải Thích': safeString(),
      })
    ).prefault({}),
    'Hợp Đồng Hiện Tại': z.record(
      safeString().describe('Tên Đơn Hàng'),
      z.object({
        'Bên Ủy Thác': safeString(),
        'Thời Hạn': safeString(),
        'Tiền Thưởng': safeString(),
        'Giải Thích': safeString(),
        'Yêu Cầu Đơn Hàng': safeString(),
      })
    ).prefault({})
  })
});

$(() => {
  registerMvuSchema(Schema);
})

entries.content:
---
Quy Tắc Cập Nhật Biến:
  Khởi Tạo Ban Đầu:
    check:
      - 【Ưu tiên cao nhất】 Khi bắt đầu trò chơi, tất cả các trường (fields) phải ưu tiên sử dụng giá trị mặc định được thiết lập sẵn hoặc để trống.
      - Phải dựa vào thông tin đầu tiên người chơi nhập vào đầu game (như Năm kịch bản, Giai cấp thân phận, Tín ngưỡng, Lãnh địa hoặc Tên Quân Đoàn lính đánh thuê) để điền ngay lập tức các trường cốt lõi như `Chế Độ Hiện Tại`, `Cục Diện Thế Giới.Thời Gian`, `Thông Tin Người Chơi` (nếu là Chế Độ Kinh Điển) hoặc `Đoàn Lính Đánh Thuê.Tổng Quan` (nếu là Chế Độ Lính Đánh Thuê). Tuyệt đối không được bỏ sót.
      - Các trường không được nhắc đến trong thông tin đầu game của người chơi phải được giữ trống hoặc ở trạng thái mặc định một cách nghiêm ngặt, chờ cốt truyện tiếp theo phát triển để điền vào. Tuyệt đối không cho phép AI tự dưng bịa đặt ra.

  Chế Độ Hiện Tại:
    type: 'Chế Độ Kinh Điển' | 'Chế Độ Lính Đánh Thuê'
    check:
      - Quyết định bảng hệ thống và logic cập nhật nào đang có hiệu lực. Ngoại trừ lúc Khởi Tạo Ban Đầu, tuyệt đối KHÔNG tự động thay đổi chế độ này, trừ khi <user> có sự chuyển đổi thân phận triệt để trong cốt truyện hoặc ra lệnh hệ thống rõ ràng.

  # ==========================================
  # 【Biến Dùng Chung Toàn Cục】 (Thông tin thế giới cơ bản phải cập nhật ở bất kỳ chế độ nào)
  # ==========================================
  Cục Diện Thế Giới:
    Thời Gian:
      type: |-
        {
          Năm: string;
          Lịch Pháp: string;
        }
      check:
        - Thiết lập ở Khởi Tạo Ban Đầu, sau đó khi các sự kiện trôi qua, Năm và ngày tháng cần được cập nhật đồng bộ.
        - Trước năm 1582, toàn bộ sử dụng Lịch Julius (ví dụ: ngày 21 tháng 6 Lịch Julius). Sau năm 1582, khu vực Tân giáo dùng Lịch Julius, khu vực Công Giáo dùng Lịch Gregory, các khu vực liên quan đến Ottoman dùng Lịch Hồi giáo.
    ${Tình Hình Hiện Tại|Khó Khăn Hiện Tại}:
      check:
        - Tình Hình Hiện Tại: Cập nhật khi có sự kiện lịch sử lớn hoặc chiến dịch diễn ra. Chế Độ Kinh Điển thiên về cục diện vĩ mô của đế quốc và phong phanh nghị viện; Chế Độ Lính Đánh Thuê thiên về chiến cục cục bộ và đối đầu phe phái.
        - Khó Khăn Hiện Tại: Cập nhật dựa trên vấn đề cấp bách nhất mà <user> đang đối mặt. Chế Độ Kinh Điển thiên về đấu đá chính trị, nổi loạn lãnh địa hoặc tòa án dị giáo; Chế Độ Lính Đánh Thuê thiên về cạn kiệt quân lương, hết lương thực hoặc bị bao vây.

  Thông Tin Người Chơi:
    Hồ Sơ Gia Tộc.${Tên|Tuổi}:
      check:
        - Thiết lập ở Khởi Tạo Ban Đầu, sau đó cập nhật Tuổi đồng bộ với sự trôi đi của Thời Gian. Đây là định danh thân phận cơ bản dùng chung toàn cục.
        - Họ Tên và thân phận sẽ được cập nhật theo tình hình thực tế khi cốt truyện phát triển hoặc trong trường hợp kế vị đặc biệt.

  # ==========================================
  # 【Biến Độc Quyền Chế Độ Kinh Điển】 (Chỉ cho phép cập nhật khi Chế Độ Hiện Tại là 'Chế Độ Kinh Điển'!)
  # ==========================================
  Cục Diện Thế Giới.Trạng Thái Vĩ Mô.${Uy Quyền Đế Quốc|Mức Phân Hóa Tôn Giáo|Mức Đe Dọa Bên Ngoài}:
    type: |-
      {
        Chỉ Số: number;
        Mô Tả: string;
      }
    range: 0~100
    check:
      - 【Chỉ cập nhật ở Chế Độ Kinh Điển】. Uy Quyền Đế Quốc chịu ảnh hưởng bởi độ phục tùng của chư hầu và quyền kiểm soát của Hoàng đế; Mức Phân Hóa Tôn Giáo chịu ảnh hưởng bởi mâu thuẫn Công Giáo - Tân giáo; Mức Đe Dọa Bên Ngoài chịu ảnh hưởng bởi động thái của Ottoman hoặc Pháp.

  Cục Diện Thế Giới.Động Thái Quốc Gia:
    type: |-
      {
        [Tên quốc gia: string]: string;
      }
    check:
      - 【Chỉ cập nhật ở Chế Độ Kinh Điển】. Ghi lại khi các quốc gia lân cận hoặc chư hầu Thánh La Mã xảy ra biến cố ngoại giao, quân sự lớn.

  Thông Tin Người Chơi:
    Bối Cảnh Cơ Bản.${Quốc Gia|Giai Cấp|Tín Ngưỡng Tôn Giáo|Lãnh Địa|Chức Vụ}:
      check:
        - 【Chỉ cập nhật ở Chế Độ Kinh Điển】. Chỉ cập nhật khi <user> có sự thay đổi thân phận thực chất như nhảy vọt giai tầng, cải đạo, có/mất lãnh địa, hoặc được phong chức vụ mới.
    Hồ Sơ Gia Tộc.${Tên Gia Tộc|Châm Ngôn Gia Tộc}:
      check:
        - 【Chỉ cập nhật ở Chế Độ Kinh Điển】. Cập nhật khi xảy ra biến cố gia tộc lớn (ví dụ: ở rể, lập nhánh gia tộc mới).
    Danh Hiệu Và Lý Lịch:
      type: |-
        {
          Danh Hiệu: { [Tên danh hiệu: string]: string; };
          Lý Lịch: { [Mốc thời gian: string]: string; };
        }
      check:
        - 【Chỉ cập nhật ở Chế Độ Kinh Điển】. Cập nhật Danh Hiệu khi được phong tước, đoạt lãnh địa hợp pháp hoặc bị tước bỏ; Thêm Lý Lịch sau khi trải qua các sự kiện lớn ảnh hưởng đến vận mệnh.

  Thuộc Tính Năng Lực.${Võ Lực|Thống Soái|Thần Học|Âm Mưu|Tài Chính|Ngoại Giao}:
    type: number
    range: -100~100
    check:
      - 【Chỉ cập nhật ở Chế Độ Kinh Điển】. Trong tình huống bình thường, biên độ tăng giảm qua các hoạt động rõ rệt là 1~2, gặp biến cố lớn biên độ tăng giảm là 3.

  Mối Quan Hệ:
    ${Nhân Mạch Cốt Lõi|Thành Viên Gia Tộc|Thuộc Hạ}:
      type: |-
        {
          [Họ Tên: string]: {
            Tuổi: number;
            Độ Hảo Cảm: number; // -100 đến 100
            Chức Vụ: string;
            Đánh Giá: string;
            Giải Thích: string;
            Võ Lực: number; // -100~100
            Thống Soái: number;
            Thần Học: number;
            Âm Mưu: number;
            Tài Chính: number;
            Ngoại Giao: number;
          }
        }
      check:
        - 【Chỉ cập nhật ở Chế Độ Kinh Điển】. Độ Hảo Cảm và Đánh Giá: Điều chỉnh dựa trên nhận thức của NPC đối với hành vi của <user> và lập trường phe phái.
        - Tính duy nhất toàn cục: Cùng một NPC chỉ có thể tồn tại ở MỘT trong các danh sách Nhân Mạch, Thành Viên Gia Tộc, Thuộc Hạ hoặc Hậu Đình, tuyệt đối không trùng lặp.
        - Nếu thay đổi thân phận (ví dụ: trở thành Thuộc Hạ), kế thừa hoàn toàn sáu chỉ số và Độ Hảo Cảm, đồng thời xóa triệt để khỏi danh sách cũ.
        - Xóa khỏi tất cả danh sách khi nhân vật tử vong hoặc biến mất hoàn toàn.
    Hậu Đình:
      type: |-
        {
          [Họ Tên: string]: {
            Tuổi: number;
            Chức Vụ: string;
            Độ Hảo Cảm: number; // -100 đến 100
            Đánh Giá: string;
            Số Lần Quan Hệ: number;
            Giải Thích: string;
          }
        }
      check:
        - 【Chỉ cập nhật ở Chế Độ Kinh Điển】. Khi gia nhập Hậu Đình, kế thừa trực tiếp Độ Hảo Cảm từ danh sách quan hệ, và xóa triệt để khỏi danh sách cũ.
        - Cập nhật Số Lần Quan Hệ sau khi phát sinh quan hệ thực chất; điều chỉnh Đánh Giá và Độ Hảo Cảm dựa trên sự bầu bạn, đãi ngộ và phân bổ lợi ích.
